  ('public-health-specialist-moex-01167', 'public-health-specialist', 'public-health-specialist-moex-114-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '關於抽樣分布（SamplingDistribution）的敘述，下列何者錯誤？', '["抽樣分布是從同一母群體中抽取所有可能樣本，並計算每個樣本的統計量後，這些統計量所形 成的分布", "抽樣分布的標準差稱為標準誤（StandardError）", "當樣本數足夠大時，樣本平均數的抽樣分布會趨近於常態分布", "樣本數越大，抽樣分布的變異性越大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "296d1f61a3ba", "answer_pdf_sha1": "ad3b9ffe7677", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
