  ('public-health-specialist-moex-01170', 'public-health-specialist', 'public-health-specialist-moex-114-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '關於信賴區間（ConfidenceInterval）的敘述，下列何者錯誤？', '["在其他條件不變下，樣本數越大，信賴區間的寬度越窄", "在其他條件不變下，信賴水準越高，信賴區間的寬度越窄", "當我們說母群體平均數的95%信賴區間時，表示此區間有95%的機率可以涵蓋到母體平均數", "研究者通常希望信賴區間越窄越好，以提供更精確的母體參數估計"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:57+00:00", "source_pdf_sha1": "296d1f61a3ba", "answer_pdf_sha1": "ad3b9ffe7677", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
